input.old_string:
@test "reads version from version.json" {
    write_version_file "1.2.3"
    run "$SCRIPT" --file "$TEST_DIR/version.json" --commits "$TEST_DIR/commits.txt" --dry-run
    [ "$status" -eq 0 ]
    [[ "$output" == *"current version: 1.2.3"* ]]
}

